        loss = mse(yhat, yb)
        grads = backward(loss)         # ∇L via chain rule
        for p, g in zip(params, grads):
            p -= eta * g               # step downhill

def run(eta, steps=20):
    x = 5.0
    for _ in range(steps):
        x -= eta * 2 * x
    return x

for eta in (0.01, 0.1, 1.01):
    print(f'eta={eta:>4}: x={run(eta):.3f}')
